    pub fn recv_(self: *_UdpSocketInner, max_bytes: usize) []const u8 {
        const buf = std.heap.page_allocator.alloc(u8, max_bytes) catch @panic("OOM");
        const msg = self.inner.receive(_io, buf) catch return buf[0..0];
        return msg.data;
